// Use parlay::map to process a sequence in parallel
// Each thread will store its ID in its thread-local instance
parlay::sequence<int> input_seq = parlay::tabulate(1000, [](size_t i){ return static_cast<int>(i); });
parlay::sequence<int> output_seq = parlay::map(input_seq, [&](int val) {
  *thread_map_ids = static_cast<int>(parlay::my_thread_id());
  // Simulate work
  std::this_thread::sleep_for (std::chrono::milliseconds (1));
  return val * 2;
});

// After the parallel map, iterate through the thread-local values
auto it = thread_map_ids.begin();
for (unsigned p = 0; p < parlay::num_thread_ids(); p++) {
  // Access the value stored by the thread corresponding to index p
  int value_at_p = *(it + p);
  // You can now process value_at_p, which should be equal to p
  // std::cout << "Value for thread " << p << " in map: " << value_at_p << std::endl;
}

