// Custom operator for sequential scan and accumulate
template <typename T>
struct TakeMax {
  T operator()(const T& a, const T& b) const {
    return std::max(a, b);
  }
};

template <typename T>
struct TakeMin {
  T operator()(const T& a, const T& b) const {
    return std::min(a, b);
  }
};

// Helper for floating point comparison
template <typename T>
bool are_approximately_equal(T a, T b, T epsilon = std::numeric_limits<T>::epsilon() * 100) {
    return std::fabs(a - b) <= epsilon * std::max(std::fabs(a), std::fabs(b));
}

int main() {
 // begin of LLM generated code

auto s = parlay::tabulate(80000, [](long long i) -> double {
  return (static_cast<double>(i) * 0.01 + 10.0);
});
auto total = parlay::scan_inclusive_inplace(s, parlay::maxm<double>());

 // end of LLM generated code

 // Add test assertions here, using `assert()` and not `ASSERT_EQ`
  // Re-generate initial sequence state for comparison
  auto initial_s_for_sequential = parlay::tabulate(80000, [](long long i) -> double {
    return (static_cast<double>(i) * 0.01 + 10.0);
  });

  // Compute sequential partial sum (max)
  auto sequential_psums = parlay::sequence<double>(80000);
  std::partial_sum(std::begin(initial_s_for_sequential), std::end(initial_s_for_sequential), std::begin(sequential_psums), TakeMax<double>());

  // Compute sequential total (max reduction)
  auto sequential_total = std::accumulate(std::begin(initial_s_for_sequential), std::end(initial_s_for_sequential), 0.0, TakeMax<double>());

  // Assertions: s was modified in place by scan_inclusive_inplace
  for (size_t i = 0; i < s.size(); ++i) {
      assert(are_approximately_equal(s[i], sequential_psums[i]));
  }
  assert(are_approximately_equal(total, sequential_total));

