template<int N>
BasicMatrix<int,N> matrix_multiply(BasicMatrix<int,N> a, const BasicMatrix<int,N>& b) { BasicMatrix<int,N> result; for (int i = 0; i < N; ++i) { for (int j = 0; j < N; ++j) { for (int k = 0; k < N; ++k) { result.data[i][j] += a.data[i][k] * b.data[k][j]; } } } return result; }
