#ifndef COMPLEX_NUMBER_H
#define COMPLEX_NUMBER_H
template<typename T>
struct ComplexNumber {
    T real, imag;
    ComplexNumber(T r = 0, T i = 0) : real(r), imag(i) {}
    static ComplexNumber zero() { return ComplexNumber(0, 0); }
    static ComplexNumber one() { return ComplexNumber(1, 0); }
    bool operator==(const ComplexNumber& other) const { return real == other.real && imag == other.imag; }
    friend std::ostream& operator<<(std::ostream& os, const ComplexNumber& c) { os << c.real << (c.imag >= 0 ? "+" : "") << c.imag << "i"; return os; }
};
template<typename T>
ComplexNumber<T> complex_add(ComplexNumber<T> a, const ComplexNumber<T>& b) { a.real += b.real; a.imag += b.imag; return a; }
template<typename T>
ComplexNumber<T> complex_multiply(ComplexNumber<T> a, const ComplexNumber<T>& b) { T new_real = a.real * b.real - a.imag * b.imag; T new_imag = a.real * b.imag + a.imag * b.real; a.real = new_real; a.imag = new_imag; return a; }
parlay::sequence<ComplexNumber<int>> get_complex_numbers() { parlay::sequence<ComplexNumber<int>> s(4); s[0] = ComplexNumber<int>(1, 2); s[1] = ComplexNumber<int>(3, 4); s[2] = ComplexNumber<int>(5, 6); s[3] = ComplexNumber<int>(7, 8); return s; }
