#ifndef VECTOR_H
#define VECTOR_H
template<typename T, int N>
struct Vector {
    T data[N];
    Vector() { for (int i = 0; i < N; ++i) data[i] = 0; }
    static Vector zero() { return Vector(); }
    static Vector min_val_vector() { Vector v; for (int i = 0; i < N; ++i) v.data[i] = std::numeric_limits<T>::min(); return v; }
    bool operator==(const Vector& other) const { for (int i = 0; i < N; ++i) if (data[i] != other.data[i]) return false; return true; }
    friend std::ostream& operator<<(std::ostream& os, const Vector& v) { os << "["; for (int i = 0; i < N; ++i) { os << v.data[i] << (i == N - 1 ? "" : ", "); } os << "]"; return os; }
};
template<int N>
Vector<int,N> vector_add(Vector<int,N> a, const Vector<int,N>& b) { for (int i = 0; i < N; ++i) a.data[i] += b.data[i]; return a; }
template<int N>
Vector<int,N> vector_max_component_wise(Vector<int,N> a, const Vector<int,N>& b) { for (int i = 0; i < N; ++i) a.data[i] = std::max(a.data[i], b.data[i]); return a; }
parlay::sequence<Vector<int,3>> get_vectors() { parlay::sequence<Vector<int,3>> s(4); s[0].data[0] = 1; s[0].data[1] = 2; s[0].data[2] = 3; s[1].data[0] = 4; s[1].data[1] = 1; s[1].data[2] = 5; s[2].data[0] = 6; s[2].data[1] = 7; s[2].data[2] = 2; s[3].data[0] = 8; s[3].data[1] = 3; s[3].data[2] = 9; return s; }
