#ifndef POLYNOMIAL_H
#define POLYNOMIAL_H
struct Polynomial {
    std::vector<int> coeffs;
    Polynomial() = default;
    Polynomial(std::initializer_list<int> c) : coeffs(c) {}
    static Polynomial zero() { return Polynomial(); }
    bool operator==(const Polynomial& other) const { auto trim = [](std::vector<int> v) { while (!v.empty() && v.back() == 0) v.pop_back(); return v; }; return trim(coeffs) == trim(other.coeffs); }
    friend std::ostream& operator<<(std::ostream& os, const Polynomial& p) { if (p.coeffs.empty()) return os << "0"; for (size_t i = 0; i < p.coeffs.size(); ++i) { if (p.coeffs[i] != 0) { if (i > 0 && p.coeffs[i] > 0) os << "+"; os << p.coeffs[i]; if (i > 0) os << "x^" << i; } } return os; }
};
Polynomial polynomial_add(Polynomial a, const Polynomial& b) { size_t max_size = std::max(a.coeffs.size(), b.coeffs.size()); a.coeffs.resize(max_size, 0); for (size_t i = 0; i < b.coeffs.size(); ++i) { a.coeffs[i] += b.coeffs[i]; } return a; }
parlay::sequence<Polynomial> get_polynomials() { parlay::sequence<Polynomial> s(3); s[0] = {1, 2}; s[1] = {3, 0, 4}; s[2] = {5}; return s; }
