template <typename T>
bool compare_sequences(const parlay::sequence<T>& a, const parlay::sequence<T>& b) {
    if (a.size() != b.size()) { std::cerr << "Sequence sizes differ: " << a.size() << " vs " << b.size() << std::endl; return false; }
    for (size_t i = 0; i < a.size(); ++i) { if (!(a[i] == b[i])) { std::cerr << "Sequences differ at index " << i << ": " << a[i] << " vs " << b[i] << std::endl; return false; } }
    return true;
}

int main() {
 const auto a = get_vectors();

struct Maxer {
  auto operator()(Vector<int,3> a, const Vector<int,3>& b) const {
    return vector_max_component_wise(std::move(a), b);
  }
};

auto vector3_max = parlay::binary_op(Maxer{}, Vector<int,3>::min_val_vector());

auto x = parlay::reduce(a, vector3_max);

 auto actual_total = std::accumulate(std::begin(a), std::end(a), Vector<int,3>::min_val_vector(), vector_max_component_wise<3>);
 assert(x == actual_total);
 std::cout << "Test passed!" << std::endl;
 return 0;
}

