#include <parlay/primitives.h>
#include <iostream>
#include <vector>
#include <algorithm>
#include <cassert>

// Custom struct for testing stable sort
struct UnstablePair {
  int x, y;
  // Default operator< is not used when a custom comparator is provided
  bool operator<(const UnstablePair& other) const {
    return x < other.x;
  }
  // Equality operator needed for comparison in assertion
  bool operator==(const UnstablePair& other) const {
      return x == other.x && y == other.y;
  }
};

int main() {
  // Setup: Generate initial sequence
  auto s = parlay::tabulate(100000, [](int i) -> UnstablePair {
    UnstablePair p;
    p.x = (53 * i + 61) % (1 << 10);
    p.y = i;
    return p;
  });

  // Keep a copy for standard library comparison
  std::vector<UnstablePair> s_std(s.begin(), s.end());

  // begin of LLM generated code

  auto sorted = parlay::stable_sort(s, [](const UnstablePair& a, const UnstablePair& b){ if (a.x != b.x) return a.x < b.x; return a.y < b.y; });

  // end of LLM generated code

  // Verification: Sort using std::stable_sort and compare
  std::stable_sort(std::begin(s_std), std::end(s_std), [](const UnstablePair& a, const UnstablePair& b){ if (a.x != b.x) return a.x < b.x; return a.y < b.y; });

  assert(s_std.size() == sorted.size());
  for(size_t i = 0; i < s_std.size(); ++i) {
      assert(s_std[i] == sorted[i]);
  }
  // Verify sorted order based on x, then y
  assert(std::is_sorted(std::begin(sorted), std::end(sorted), [](const UnstablePair& a, const UnstablePair& b){ if (a.x != b.x) return a.x < b.x; return a.y < b.y; }));

  std::cout << "Test passed!" << std::endl;

  return 0;
}

